#include <stdio.h>
#include <stdlib.h>

int main() {
    int n, *arr;
    printf("Enter size: ");
    scanf("%d", &n);

    // Allocate memory for n integers
    arr = (int*)malloc(n * sizeof(int));

    if (arr == NULL) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Initialize and display
    for (int i = 0; i < n; i++) {
        arr[i] = i + 1;
    }

    // Free allocated memory
    free(arr);
    return 0;
}

#define MAX_DEGREE 100

void addPolynomials(int poly1[], int poly2[], int result[], int maxDegree) {
    for (int i = 0; i <= maxDegree; i++) {
        result[i] = poly1[i] + poly2[i];
    }
}

// Example: poly1 = 3x² + 2x + 5 stored as [5, 2, 3]
// poly2 = x³ + 4x + 1 stored as [1, 4, 0, 1]
void displayPolynomial(int poly[], int degree) {
    for (int i = degree; i >= 0; i--) {
        if (poly[i] != 0) {
            printf("%dx%d ", poly[i], i);
            if (i > 0) printf("+ ");
        }
    }
    printf("\n");
}

#define MAX_NONZERO 100

typedef struct {
    int row;
    int col;
    int value;
} Element;

typedef struct {
    int rows;
    int cols;
    int num;
    Element elements[MAX_NONZERO];
} SparseMatrix;

void createSparseMatrix(SparseMatrix *s, int matrix[4][4], int r, int c) {
    s->rows = r;
    s->cols = c;
    s->num = 0;

    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) {
            if (matrix[i][j] != 0) {
                s->elements[s->num].row = i;
                s->elements[s->num].col = j;
                s->elements[s->num].value = matrix[i][j];
                s->num++;
            }
        }
    }
}
